import SwiftUI

/// View for creating new challenges
struct CreateChallengeView: View {\n    \n    // MARK: - Properties\n    \n    let onChallengeCreated: (ChallengeCreationData) -> Void\n    \n    // MARK: - State\n    \n    @Environment(\\.dismiss) private var dismiss\n    @State private var name = \"\"\n    @State private var description = \"\"\n    @State private var endDate = Calendar.current.date(byAdding: .day, value: 30, to: Date()) ?? Date()\n    @State private var showingDatePicker = false\n    @State private var isCreating = false\n    \n    // MARK: - Computed Properties\n    \n    private var isValid: Bool {\n        let challengeData = ChallengeCreationData(\n            name: name,\n            description: description.isEmpty ? nil : description,\n            endDate: endDate\n        )\n        return challengeData.isValid\n    }\n    \n    private var nameCharacterCount: Int {\n        name.count\n    }\n    \n    private var descriptionCharacterCount: Int {\n        description.count\n    }\n    \n    // MARK: - Body\n    \n    var body: some View {\n        NavigationView {\n            ScrollView {\n                VStack(alignment: .leading, spacing: 24) {\n                    // Header\n                    headerView\n                    \n                    // Form\n                    formView\n                    \n                    Spacer(minLength: 100)\n                }\n                .padding(24)\n            }\n            .navigationTitle(\"New Challenge\")\n            .navigationBarTitleDisplayMode(.inline)\n            .toolbar {\n                ToolbarItem(placement: .navigationBarLeading) {\n                    Button(\"Cancel\") {\n                        dismiss()\n                    }\n                }\n                \n                ToolbarItem(placement: .navigationBarTrailing) {\n                    Button(\"Create\") {\n                        createChallenge()\n                    }\n                    .disabled(!isValid || isCreating)\n                }\n            }\n            .disabled(isCreating)\n        }\n    }\n    \n    // MARK: - Header View\n    \n    private var headerView: some View {\n        VStack(alignment: .leading, spacing: 8) {\n            Text(\"Create a Challenge\")\n                .font(.title2)\n                .fontWeight(.bold)\n                .foregroundColor(.primary)\n            \n            Text(\"Design a challenge to motivate yourself and others to achieve a goal.\")\n                .font(.body)\n                .foregroundColor(.secondary)\n                .fixedSize(horizontal: false, vertical: true)\n        }\n    }\n    \n    // MARK: - Form View\n    \n    private var formView: some View {\n        VStack(alignment: .leading, spacing: 20) {\n            // Challenge Name\n            nameSection\n            \n            // Description\n            descriptionSection\n            \n            // End Date\n            endDateSection\n        }\n    }\n    \n    // MARK: - Name Section\n    \n    private var nameSection: some View {\n        VStack(alignment: .leading, spacing: 8) {\n            HStack {\n                Text(\"Challenge Name\")\n                    .font(.headline)\n                    .fontWeight(.semibold)\n                    .foregroundColor(.primary)\n                \n                Text(\"*\")\n                    .font(.headline)\n                    .foregroundColor(.red)\n                \n                Spacer()\n                \n                Text(\"\\(nameCharacterCount)/100\")\n                    .font(.caption)\n                    .foregroundColor(nameCharacterCount > 100 ? .red : .secondary)\n            }\n            \n            TextField(\"Enter challenge name\", text: $name)\n                .textFieldStyle(RoundedBorderTextFieldStyle())\n                .font(.body)\n                .autocapitalization(.words)\n                .disableAutocorrection(false)\n            \n            if nameCharacterCount > 100 {\n                Text(\"Challenge name is too long\")\n                    .font(.caption)\n                    .foregroundColor(.red)\n            } else if !name.isEmpty && name.trimmingCharacters(in: .whitespacesAndNewlines).count < 3 {\n                Text(\"Challenge name must be at least 3 characters\")\n                    .font(.caption)\n                    .foregroundColor(.red)\n            }\n        }\n    }\n    \n    // MARK: - Description Section\n    \n    private var descriptionSection: some View {\n        VStack(alignment: .leading, spacing: 8) {\n            HStack {\n                Text(\"Description\")\n                    .font(.headline)\n                    .fontWeight(.semibold)\n                    .foregroundColor(.primary)\n                \n                Spacer()\n                \n                Text(\"\\(descriptionCharacterCount)/500\")\n                    .font(.caption)\n                    .foregroundColor(descriptionCharacterCount > 500 ? .red : .secondary)\n            }\n            \n            ZStack(alignment: .topLeading) {\n                RoundedRectangle(cornerRadius: 8)\n                    .stroke(Color(UIColor.separator), lineWidth: 1)\n                    .background(\n                        RoundedRectangle(cornerRadius: 8)\n                            .fill(Color(UIColor.systemBackground))\n                    )\n                    .frame(minHeight: 100)\n                \n                if description.isEmpty {\n                    Text(\"Describe your challenge (optional)\")\n                        .font(.body)\n                        .foregroundColor(.secondary)\n                        .padding(.horizontal, 12)\n                        .padding(.vertical, 8)\n                }\n                \n                TextEditor(text: $description)\n                    .font(.body)\n                    .padding(.horizontal, 8)\n                    .padding(.vertical, 4)\n                    .background(Color.clear)\n                    .autocapitalization(.sentences)\n            }\n            \n            if descriptionCharacterCount > 500 {\n                Text(\"Description is too long\")\n                    .font(.caption)\n                    .foregroundColor(.red)\n            }\n        }\n    }\n    \n    // MARK: - End Date Section\n    \n    private var endDateSection: some View {\n        VStack(alignment: .leading, spacing: 8) {\n            Text(\"End Date\")\n                .font(.headline)\n                .fontWeight(.semibold)\n                .foregroundColor(.primary)\n            \n            Button(action: {\n                showingDatePicker = true\n            }) {\n                HStack {\n                    Image(systemName: \"calendar\")\n                        .font(.body)\n                        .foregroundColor(.accentColor)\n                    \n                    Text(DateFormatter.challengeDate.string(from: endDate))\n                        .font(.body)\n                        .foregroundColor(.primary)\n                    \n                    Spacer()\n                    \n                    Image(systemName: \"chevron.right\")\n                        .font(.caption)\n                        .foregroundColor(.secondary)\n                }\n                .padding(.horizontal, 12)\n                .padding(.vertical, 10)\n                .background(\n                    RoundedRectangle(cornerRadius: 8)\n                        .stroke(Color(UIColor.separator), lineWidth: 1)\n                        .background(\n                            RoundedRectangle(cornerRadius: 8)\n                                .fill(Color(UIColor.systemBackground))\n                        )\n                )\n            }\n            .sheet(isPresented: $showingDatePicker) {\n                datePickerSheet\n            }\n            \n            if endDate <= Date() {\n                Text(\"End date must be in the future\")\n                    .font(.caption)\n                    .foregroundColor(.red)\n            }\n        }\n    }\n    \n    // MARK: - Date Picker Sheet\n    \n    private var datePickerSheet: some View {\n        NavigationView {\n            VStack {\n                DatePicker(\n                    \"End Date\",\n                    selection: $endDate,\n                    in: Date()...,\n                    displayedComponents: .date\n                )\n                .datePickerStyle(WheelDatePickerStyle())\n                .labelsHidden()\n                \n                Spacer()\n            }\n            .padding()\n            .navigationTitle(\"End Date\")\n            .navigationBarTitleDisplayMode(.inline)\n            .toolbar {\n                ToolbarItem(placement: .navigationBarLeading) {\n                    Button(\"Cancel\") {\n                        showingDatePicker = false\n                    }\n                }\n                \n                ToolbarItem(placement: .navigationBarTrailing) {\n                    Button(\"Done\") {\n                        showingDatePicker = false\n                    }\n                }\n            }\n        }\n        .presentationDetents([.medium])\n    }\n    \n    // MARK: - Actions\n    \n    private func createChallenge() {\n        guard isValid else { return }\n        \n        isCreating = true\n        \n        let challengeData = ChallengeCreationData(\n            name: name.trimmingCharacters(in: .whitespacesAndNewlines),\n            description: description.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? nil : description.trimmingCharacters(in: .whitespacesAndNewlines),\n            endDate: endDate\n        )\n        \n        onChallengeCreated(challengeData)\n        \n        // Add a small delay to show the creating state\n        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {\n            dismiss()\n        }\n    }\n}\n\n// MARK: - Preview\n\n#Preview {\n    CreateChallengeView { challengeData in\n        print(\"Created challenge: \\(challengeData.name)\")\n    }\n}\n\n#Preview(\"With Data\") {\n    struct PreviewWrapper: View {\n        @State private var showingCreate = true\n        \n        var body: some View {\n            Button(\"Show Create Challenge\") {\n                showingCreate = true\n            }\n            .sheet(isPresented: $showingCreate) {\n                CreateChallengeView { challengeData in\n                    print(\"Created challenge: \\(challengeData.name)\")\n                }\n            }\n        }\n    }\n    \n    return PreviewWrapper()\n}"